     * to U+001F are escaped (\b, \t, \n, \f, \r use short form; others use \u00XX). ECMAScript's `JSON.parse` does
     * recover escaped unicode characters that are not in this range, but other tooling may provide different results.
     */
    function escapeJSON(string memory input) internal pure returns (string memory) {
        bytes memory buffer = bytes(input);

        // Put output at the FMP. Memory will be reserved later when we figure out the actual length of the escaped
        // string. All write are done using _unsafeWriteBytesOffset, which avoid the (expensive) length checks for
        // each character written.
        bytes memory output;
        assembly ("memory-safe") {
            output := mload(0x40)
        }
        uint256 outputLength = 0;

        for (uint256 i = 0; i < buffer.length; ++i) {
            uint8 char = uint8(bytes1(_unsafeReadBytesOffset(buffer, i)));
            if (((SPECIAL_CHARS_LOOKUP & (1 << char)) != 0)) {
                _unsafeWriteBytesOffset(output, outputLength++, "\\");
                if (char == 0x08) _unsafeWriteBytesOffset(output, outputLength++, "b");
                else if (char == 0x09) _unsafeWriteBytesOffset(output, outputLength++, "t");
                else if (char == 0x0a) _unsafeWriteBytesOffset(output, outputLength++, "n");
                else if (char == 0x0c) _unsafeWriteBytesOffset(output, outputLength++, "f");
                else if (char == 0x0d) _unsafeWriteBytesOffset(output, outputLength++, "r");
                else if (char == 0x5c) _unsafeWriteBytesOffset(output, outputLength++, "\\");
                else if (char == 0x22) {
                    // solhint-disable-next-line quotes
                    _unsafeWriteBytesOffset(output, outputLength++, '"');
                } else {
                    // U+0000 to U+001F without short form: output \u00XX
                    _unsafeWriteBytesOffset(output, outputLength++, "u");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char >> 4]);
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char & 0x0f]);
                }
            } else {
                _unsafeWriteBytesOffset(output, outputLength++, bytes1(char));
            }
        }
        // write the actual length and reserve memory
        assembly ("memory-safe") {
            mstore(output, outputLength)
            mstore(0x40, add(output, add(outputLength, 0x20)))
        }

        return string(output);
    }

    /**
     * @dev Reads a bytes32 from a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeReadBytesOffset(bytes memory buffer, uint256 offset) private pure returns (bytes32 value) {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            value := mload(add(add(buffer, 0x20), offset))
        }
    }

    /**
     * @dev Write a bytes1 to a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeWriteBytesOffset(bytes memory buffer, uint256 offset, bytes1 value) private pure {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            mstore8(add(add(buffer, 0x20), offset), shr(248, value))
        }
    }
}

contracts/AetherialVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "./AgentRegistry.sol";

/**
 * @title AetherialVault
 * @dev The core liquidity pool for Aetherial Prime Broker.
 *
 *  Yield mechanics:
 *   - LPs deposit AUSD and receive a proportional share of the vault.
 *   - Profit splitting: 5% protocol, 10% agent, 85% LPs.
 *
 *  Slashing mechanics:
 *   - Proportional slashing: score_reduction = loss_pct * (2 + consecutiveLosses).
 *   - Recovery: Streak resets only if profit >= 5% of allocation.
 */
contract AetherialVault is ReentrancyGuard, AccessControl {
    bytes32 public constant MANAGER_ROLE = keccak256("MANAGER_ROLE");

    AgentRegistry public registry;
    IERC20 public asset;

    // ── Config ──────────────────────────────────────────────────────────────
    uint256 public constant PROTOCOL_FEE_BPS = 500;   // 5%
    uint256 public constant AGENT_FEE_BPS    = 1000;  // 10%
    uint256 public constant BPS_DENOMINATOR  = 10000;

    /// Reset streak if profit >= 5% of allocation
    uint256 public constant MIN_PROFIT_BPS_TO_RESET = 500; 
    uint256 public constant MAX_ALLOCATION_BPS = 2000;

    // ── LP accounting ────────────────────────────────────────────────────────
    uint256 public totalShares;
    mapping(address => uint256) public lpShares;
    uint256 public accRewardPerShare;
    mapping(address => uint256) public rewardDebt;
    mapping(address => uint256) public pendingYield;

    // ── Agent accounting ─────────────────────────────────────────────────────
    uint256 public totalAllocated;
    mapping(address => uint256) public activeAllocations;
    mapping(address => uint256) public consecutiveLosses;

    // ── Treasury ─────────────────────────────────────────────────────────────
    address public treasury;
    uint256 public protocolFeeAccrued;

    // ── Events ───────────────────────────────────────────────────────────────
    event Deposited(address indexed lp, uint256 amount, uint256 shares);
    event Withdrawn(address indexed lp, uint256 amount, uint256 shares);
    event YieldClaimed(address indexed lp, uint256 amount);
    event LiquidityAllocated(address indexed agent, uint256 amount);
    event LiquiditySettled(address indexed agent, uint256 repayment, uint256 profit, uint256 loss);
    event ProtocolFeeWithdrawn(address indexed treasury, uint256 amount);

    constructor(
        address _registry,
        address _asset,
        address _treasury
    ) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MANAGER_ROLE, msg.sender);

        registry = AgentRegistry(_registry);
        asset = IERC20(_asset);
        treasury = _treasury;
    }

    // ── Internal helpers ─────────────────────────────────────────────────────

    function totalAssets() public view returns (uint256) {
        return asset.balanceOf(address(this)) - protocolFeeAccrued + totalAllocated;
    }

    function _toShares(uint256 amount) internal view returns (uint256) {
        uint256 pool = totalAssets() - amount; // assets before this deposit
        if (totalShares == 0 || pool == 0) return amount;
        return (amount * totalShares) / pool;
    }

    function _toAssets(uint256 shares) internal view returns (uint256) {
        if (totalShares == 0) return 0;
        return (shares * totalAssets()) / totalShares;
    }

    function _harvest(address lp) internal {
        if (lpShares[lp] > 0) {
            uint256 earned = (lpShares[lp] * accRewardPerShare) / 1e18 - rewardDebt[lp];
            if (earned > 0) pendingYield[lp] += earned;
        }
        rewardDebt[lp] = (lpShares[lp] * accRewardPerShare) / 1e18;
    }

    // ── LP functions ─────────────────────────────────────────────────────────

    function deposit(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be > 0");
        _harvest(msg.sender);

        asset.transferFrom(msg.sender, address(this), amount);
        uint256 shares = _toShares(amount);
        lpShares[msg.sender] += shares;
        totalShares += shares;

        rewardDebt[msg.sender] = (lpShares[msg.sender] * accRewardPerShare) / 1e18;
        emit Deposited(msg.sender, amount, shares);
    }

    function withdraw(uint256 shares) external nonReentrant {
        require(shares > 0 && lpShares[msg.sender] >= shares, "Invalid shares");
        _harvest(msg.sender);

        uint256 amount = (shares * totalAssets()) / totalShares;
        uint256 available = asset.balanceOf(address(this)) - protocolFeeAccrued;
        require(amount <= available, "Insufficient liquid assets");

        lpShares[msg.sender] -= shares;
        totalShares -= shares;

        rewardDebt[msg.sender] = (lpShares[msg.sender] * accRewardPerShare) / 1e18;
        asset.transfer(msg.sender, amount);
        emit Withdrawn(msg.sender, amount, shares);
    }

    function claimYield() external nonReentrant {
        _harvest(msg.sender);
        uint256 amount = pendingYield[msg.sender];
        require(amount > 0, "No yield to claim");
        pendingYield[msg.sender] = 0;
        asset.transfer(msg.sender, amount);
        emit YieldClaimed(msg.sender, amount);
    }

    // ── Agent functions ───────────────────────────────────────────────────────

    function requestLiquidity(uint256 amount) external nonReentrant {
        AgentRegistry.Agent memory agent = registry.getAgent(msg.sender);
        require(agent.isWhitelisted, "Agent not whitelisted");
        require(amount > 0, "Amount > 0");

        uint256 liquid = asset.balanceOf(address(this)) - protocolFeeAccrued;
        require(amount <= liquid, "Insufficient liquid assets");

        uint256 maxAlloc = (totalAssets() * MAX_ALLOCATION_BPS) / BPS_DENOMINATOR;
        require(activeAllocations[msg.sender] + amount <= maxAlloc, "Exceeds max allocation");

        activeAllocations[msg.sender] += amount;
        totalAllocated += amount;

        asset.transfer(msg.sender, amount);
        emit LiquidityAllocated(msg.sender, amount);
    }

    function settleLiquidity(uint256 repaymentAmount) external nonReentrant {
        uint256 allocation = activeAllocations[msg.sender];
        require(allocation > 0, "No active allocation");

        asset.transferFrom(msg.sender, address(this), repaymentAmount);
        activeAllocations[msg.sender] = 0;
        totalAllocated -= allocation;

        if (repaymentAmount >= allocation) {
            uint256 profit = repaymentAmount - allocation;

            // Handle Grace condition for Streak Reset
            uint256 profitBps = (profit * BPS_DENOMINATOR) / allocation;
            if (profitBps >= MIN_PROFIT_BPS_TO_RESET) {
                consecutiveLosses[msg.sender] = 0;
            }

            if (profit > 0 && totalShares > 0) {
                uint256 protocolFee = (profit * PROTOCOL_FEE_BPS) / BPS_DENOMINATOR;
                uint256 agentFee    = (profit * AGENT_FEE_BPS)    / BPS_DENOMINATOR;
                uint256 lpProfit    = profit - protocolFee - agentFee;

                protocolFeeAccrued += protocolFee;
                if (agentFee > 0) asset.transfer(msg.sender, agentFee);
                if (lpProfit > 0) accRewardPerShare += (lpProfit * 1e18) / totalShares;
            }
            emit LiquiditySettled(msg.sender, repaymentAmount, profit, 0);
        } else {
            uint256 loss = allocation - repaymentAmount;
            uint256 lossPct = (loss * 100) / allocation;
            uint256 slashPoints = lossPct * (2 + consecutiveLosses[msg.sender]);

            consecutiveLosses[msg.sender]++;
            registry.slashAgent(msg.sender, slashPoints);

            emit LiquiditySettled(msg.sender, repaymentAmount, 0, loss);
        }
    }

    // ── Admin functions ───────────────────────────────────────────────────────

    function withdrawProtocolFees() external onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256 amount = protocolFeeAccrued;
        require(amount > 0, "No fees");
        protocolFeeAccrued = 0;
        asset.transfer(treasury, amount);
        emit ProtocolFeeWithdrawn(treasury, amount);
    }

    function setTreasury(address _treasury) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_treasury != address(0), "Zero address");
        treasury = _treasury;
    }
}

contracts/AgentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "./ReputationNFT.sol";

/**
 * @title AgentRegistry
 * @dev Manages agent identities, credit scores, and Reputation NFTs on Aetherial.
 *
 *  Flow:
 *   1. Agent calls registerAgent() → stored with score 0, not whitelisted.
 *   2. Manager calls updateCreditScore() with the real alpha score.
 *   3. If score >= WHITELIST_THRESHOLD the agent is auto-whitelisted.
 *   4. On first whitelist, a soulbound ReputationNFT is minted with the EAS UID.
 */
contract AgentRegistry is AccessControl {
    bytes32 public constant MANAGER_ROLE = keccak256("MANAGER_ROLE");

    ReputationNFT public reputationNFT;

    /// Minimum credit score (0-1000) required for auto-whitelist
    uint256 public constant WHITELIST_THRESHOLD = 500;

    struct Agent {
        bool isRegistered;
        uint256 creditScore;   // 0-1000
        string easAttestationUID; 
        bool isWhitelisted;
        uint256 lastUpdated;
    }

    mapping(address => Agent) public agents;
    address[] public registeredAgents;

    event AgentRegistered(address indexed agent);
    event CreditScoreUpdated(address indexed agent, uint256 newScore, string easUID);
    event WhitelistStatusChanged(address indexed agent, bool status);
    event AgentSlashed(address indexed agent, uint256 slashPoints, uint256 newScore);

    constructor(address _reputationNFT) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MANAGER_ROLE, msg.sender);
        reputationNFT = ReputationNFT(_reputationNFT);
    }

    /**
     * @dev Any address can self-register as an agent.
     */
    function registerAgent() external {
        require(!agents[msg.sender].isRegistered, "Already registered");
        agents[msg.sender] = Agent({
            isRegistered: true,
            creditScore: 0,
            easAttestationUID: "",
            isWhitelisted: false,
            lastUpdated: block.timestamp
        });
        registeredAgents.push(msg.sender);
        emit AgentRegistered(msg.sender);
    }

    /**
     * @dev Called by the off-chain manager after computing alpha score.
     */
    function updateCreditScore(
        address agent,
        uint256 score,
        string calldata easUID
    ) external onlyRole(MANAGER_ROLE) {
        require(agents[agent].isRegistered, "Agent not registered");
        require(score <= 1000, "Score out of range");

        agents[agent].creditScore = score;
        agents[agent].easAttestationUID = easUID;
        agents[agent].lastUpdated = block.timestamp;

        emit CreditScoreUpdated(agent, score, easUID);

        _updateWhitelistAndNFT(agent, score, easUID);
    }

    /**
     * @dev Process protocol-level slashing for bad performance or losses.
     */
    function slashAgent(address agent, uint256 points) external onlyRole(MANAGER_ROLE) {
        require(agents[agent].isRegistered, "Agent not registered");

        if (points > agents[agent].creditScore) {
            agents[agent].creditScore = 0;
        } else {
            agents[agent].creditScore -= points;
        }

        emit AgentSlashed(agent, points, agents[agent].creditScore);

        _updateWhitelistAndNFT(agent, agents[agent].creditScore, agents[agent].easAttestationUID);
    }

    function _updateWhitelistAndNFT(address agent, uint256 score, string memory easUID) internal {
        bool shouldWhitelist = score >= WHITELIST_THRESHOLD;
        if (agents[agent].isWhitelisted != shouldWhitelist) {
            agents[agent].isWhitelisted = shouldWhitelist;
            emit WhitelistStatusChanged(agent, shouldWhitelist);
        }

        // Mint or update Reputation NFT
        if (reputationNFT.agentTokenId(agent) == 0) {
            reputationNFT.mintReputation(agent, easUID);
        } else {
            reputationNFT.updateReputation(agent, easUID);
        }
    }

    /**
     * @dev Manual override — admin can force whitelist status regardless of score.
     */
    function setWhitelisted(address agent, bool status) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(agents[agent].isRegistered, "Agent not registered");
        agents[agent].isWhitelisted = status;
        emit WhitelistStatusChanged(agent, status);
    }

    function getAgent(address agent) external view returns (Agent memory) {
        return agents[agent];
    }

    function getRegisteredAgents() external view returns (address[] memory) {
        return registeredAgents;
    }

    function totalAgents() external view returns (uint256) {
        return registeredAgents.length;
    }
}

contracts/ReputationNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title ReputationNFT
 * @dev Soulbound ERC-721 that represents a verified agent's on-chain reputation.
 *      - One NFT per agent address (non-transferable after mint).
 *      - The AgentRegistry (owner) mints/updates the token URI when credit score changes.
 *      - tokenURI stores the EAS attestation UID so it is permanently auditable.
 */
contract ReputationNFT is ERC721, Ownable {
    uint256 private _nextTokenId;

    // agent address → token id
    mapping(address => uint256) public agentTokenId;
    // token id → metadata URI (EAS attestation UID encoded as URI)
    mapping(uint256 => string) private _tokenURIs;

    event ReputationMinted(address indexed agent, uint256 tokenId, string attestationUID);
    event ReputationUpdated(address indexed agent, uint256 tokenId, string newAttestationUID);

    constructor() ERC721("Aetherial Reputation", "AREP") Ownable(msg.sender) {}

    /**
     * @dev Mint a Reputation NFT for a new agent. Only callable by AgentRegistry (owner).
     */
    function mintReputation(address agent, string calldata attestationUID) external onlyOwner returns (uint256) {
        require(agentTokenId[agent] == 0, "Reputation already minted");

        _nextTokenId++;
        uint256 tokenId = _nextTokenId;

        _safeMint(agent, tokenId);
        _tokenURIs[tokenId] = attestationUID;
        agentTokenId[agent] = tokenId;

        emit ReputationMinted(agent, tokenId, attestationUID);
        return tokenId;
    }

    /**
     * @dev Update the attestation URI when credit score is refreshed.
     */
    function updateReputation(address agent, string calldata newAttestationUID) external onlyOwner {
        uint256 tokenId = agentTokenId[agent];
        require(tokenId != 0, "No reputation NFT found");
        _tokenURIs[tokenId] = newAttestationUID;
        emit ReputationUpdated(agent, tokenId, newAttestationUID);
    }

    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        require(_ownerOf(tokenId) != address(0), "Token does not exist");
        return _tokenURIs[tokenId];
    }

    /// @dev Soulbound: block all transfers except mint (from == address(0))
    function _update(
        address to,
        uint256 tokenId,
        address auth
    ) internal override returns (address) {
        address from = _ownerOf(tokenId);
        require(from == address(0), "Reputation NFT is soulbound");
        return super._update(to, tokenId, auth);
    }
}

